import java.io.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        int T = 1;
        if (line != null && !line.trim().isEmpty()) {
            try {
                T = Integer.parseInt(line.trim());
            } catch (NumberFormatException e) {
                T = 1;
            }
        }
        String[] lines = {
            "r: Read a file.",
            "w: Write a file.",
            "a: Append to a file.",
            "r+: Read and write a file.",
            "w+: Write and read a file.",
            "a+: Append and read a file.",
            "b: Binary mode.",
            "t: Text mode.",
            "rb: Read a binary file.",
            "wb: Write a binary file.",
            "ab: Append to a binary file.",
            "r+b: Read and write a binary file.",
            "w+b: Write and read a binary file.",
            "a+b: Append and read a binary file."
        };
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            for (String s : lines) {
                sb.append(s).append('\n');
            }
            if (tc != T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

